class Solution:
    def findBestValue(self, arr: List[int], target: int) -> int:
        arr.sort()
        left, right = 0, max(arr)
        while left <= right:
            mid = (left + right) // 2
            total = sum(min(x, mid) for x in arr)
            if total == target:
                return mid
            elif total < target:
                left = mid + 1
            else:
                right = mid - 1
        if target - sum(min(x, left - 1) for x in arr) <= sum(min(x, right) for x in arr) - target:
            return left - 1
        return right
```

